(() => {
  const grid = document.querySelector("#searchResults");
  const input = document.querySelector("#searchInput");
  const year = document.querySelector("#searchYear");
  const region = document.querySelector("#searchRegion");
  const genre = document.querySelector("#searchGenre");
  if (!grid || !input) return;

  const params = new URLSearchParams(location.search);
  input.value = params.get("q") || "";

  const card = (item) => `
        <article class="movie-card" data-title="${escapeHtml(item.title)}" data-year="${escapeHtml(item.year)}" data-region="${escapeHtml(item.region)}" data-genre="${escapeHtml(item.genre)}">
          <a class="poster-link" href="${escapeAttr(item.url)}" aria-label="${escapeAttr(item.title)}">
            <img src="${escapeAttr(item.cover)}" alt="${escapeAttr(item.title)}" loading="lazy">
            <span class="poster-badge">${escapeHtml(item.year)}</span>
          </a>
          <div class="card-body">
            <div class="card-meta">
              <a href="${escapeAttr(item.categoryUrl)}">${escapeHtml(item.category)}</a>
              <span>${escapeHtml(item.region)}</span>
            </div>
            <h3><a href="${escapeAttr(item.url)}">${escapeHtml(item.title)}</a></h3>
            <p>${escapeHtml(item.one)}</p>
            <div class="tag-row"><span>${escapeHtml(item.type)}</span><span>${escapeHtml(item.genre)}</span></div>
          </div>
        </article>`;

  function escapeHtml(value) {
    return String(value || "").replace(/[&<>"']/g, (ch) => ({ "&": "&amp;", "<": "&lt;", ">": "&gt;", "\"": "&quot;", "'": "&#39;" }[ch]));
  }

  function escapeAttr(value) {
    return escapeHtml(value);
  }

  function render() {
    const q = input.value.trim().toLowerCase();
    const yearValue = year.value;
    const regionValue = region.value;
    const genreValue = genre.value;
    const result = MOVIE_INDEX.filter((item) => {
      const hay = [item.title, item.year, item.region, item.type, item.genre, item.one, item.category].join(" ").toLowerCase();
      return (!q || hay.includes(q)) && (!yearValue || item.year === yearValue) && (!regionValue || item.region === regionValue) && (!genreValue || item.genre.includes(genreValue));
    }).slice(0, 120);
    grid.innerHTML = result.map(card).join("");
  }

  [input, year, region, genre].forEach((el) => el.addEventListener("input", render));
  render();
})();
